#############################################
## DBsubject()
## DBchapter()
## DBsection()
## Level()
## KEYWORDS()
## TitleText1()
## EditionText1()
## AuthorText1()
## Section1(not reported)
## Problem1(1.5.8.77)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context("Fraction")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
parser::Assignment->Allow;
do {
  do {
      $m[0] = Fraction(random_coprime([1..5],[2..6]));
      $m[1] = Fraction(random_coprime([1..5],[2..6]));
  } until ($m[0] != $m[1]);
  @b = map{Fraction(random_coprime([-5..-1,1..5],[2..6]))} (0,1);
  $i = random(0,1);
  $b[$i] = Fraction(random_coprime([-5..-1,1..5],[($m[1-$i]->value)[1]]));
  $x = Fraction(($b[0] - $b[1])/($m[1] - $m[0]));
  $y = Fraction(($m[1]*$b[0] - $m[0]*$b[1])/($m[1] - $m[0]));
} until (($x->value)[1] <= 50 && ($y->value)[1] <= 50);
$xis = Formula("$X = $x");
$yis = Formula("$Y = $y");
$solution = List($xis,$yis);
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$answer = $solution->cmp(
  mathQuillOpts => 'disabled'
);
@right = map{Formula("$m[$_] $X + $b[$_]")->reduce} (0,1);
@f = map{Formula("$Y = $right[$_]")} (0,1);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$f[0]] \\
                  \amp [$f[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
